const reverseWords = s => {
    let start = s.length - 1
    let end = s.length - 1
    let ret = ''

    const tmp = s.trim()

    while (start >= 0) {
        while (start >= 0 && !/ /.test(tmp[start])) {
            start--
        }

        ret += tmp.slice(start + 1, end + 1) + ' '

        while (start >= 0 && / /.test(tmp[start])) {
            start--
        }
        end = start
    }

    return ret.trim()
}
